When building production-ready Django applications, writing robust unit tests is non-negotiable. A well-structured unit testing strategy ensures:Changes don’t break existing functionality.Business logic works as expected.You have confidence in refactoring.
This guide walks through how to write scalable unit tests using a structured and reusable pattern—complete with mock data, a shared test base, map factories, and advanced mocking techniques like MagicMock and @patch.


  Project Test Structure Overview
Let’s use a modular and DRY (Don’t Repeat Yourself) structure for our Django test suite:your_project/
├── base_test/
│   ├── base_map_factory.py
│   ├── constant_model_map.py
│   └── base_test_case.py
├── your_app/
│   │   ├── maps/
│   │   │   └── merchant_map.py
│   │   └── test_send_key_salt.py


  🔧 1. Base Map Factory — Reusable Test Data Provider
📁 base_test/base_map_factory.pyimport copy

class BaseMapFactory:
    def __init__(self, map=None):
        self.map = map or {}
    def get_map(self, key=None, updates={}):
        try:
            data = self.map
            for k in key:
                data = copy.deepcopy(data[k])
            if updates:
                if isinstance(data, list):
                    for item in data:
                        item.update(updates)
                elif isinstance(data, dict):
                    data.update(updates)
            return data
        except (KeyError, TypeError) as e:
            print("Error fetching map:", e)
            return None
Encapsulates test data in an extendable pattern.Prevents mutation of original data.Enables easy overrides using updates.


  2. Constant Test Data for DB Models
📁 base_test/constant_model_map.pyfrom base_test.base_map_factory import BaseMapFactory

class ConstantModelMap(BaseMapFactory):
    def __init__(self):
        self.map = {
            "merchant_credentials": {
                "id": 1,
                "merchant_id": "EXAMPLE123",
                "api_key": "secureapikey",
                "callback_url": "https://callback.test.com"
            },
            "merchant_info": {
                "merchant_id": 123,
                "merchant_name": "Test Merchant",
                "email": "merchant@example.com"
            }
        }
        super().__init__(self.map)
Maintains a single source of truth for model test data.Easy to maintain and change without digging into tests.


  🧪 3. Shared Base Test Case
📁 base_test/base_test_case.pyfrom django.test import TestCase, Client
from base_test.constant_model_map import ConstantModelMap
from your_app.models import Merchant, MerchantCredentials

class BaseDjangoTestCase(TestCase):
    @classmethod
    def setUpClass(cls):
        super().setUpClass()
        cls.client = Client()
        cls.models_map = ConstantModelMap()

        cls.merchant = Merchant.objects.create(
            **cls.models_map.get_map(["merchant_info"])
        )
        cls.credentials = MerchantCredentials.objects.create(
            **cls.models_map.get_map(["merchant_credentials"])
        )

Promotes code reuse across test files.Sets up test models in a shared, structured way.


  💼 4. Map for Service/API-Specific Static Data
📁 your_app/tests/maps/merchant_map.pyfrom base_test.base_map_factory import BaseMapFactory

class MerchantTestMap(BaseMapFactory):
    def __init__(self):
        self.map = {
            "common_request_data": {
                "merchant_id": 123,
                "key": "value"
            },
            "successful_response": {
                "status": "success",
                "data": {"message": "Key sent"}
            },
            "error_response": {
                "status": "error",
                "data": {"message": "Invalid merchant_id"}
            }
        }
        super().__init__(self.map)




  🚀 5. Test File — Using All the Building Blocks
📁 your_app/tests/test_send_key_salt.pyfrom django.urls import reverse
from unittest.mock import patch, MagicMock

from base_test.base_test_case import BaseDjangoTestCase
from your_app.tests.maps.merchant_map import MerchantTestMap
from shared.utility.loggers.logging import AppLogger
from shared.utility.push import Push

class SendKeySaltTests(BaseDjangoTestCase):
    @classmethod
    def setUpClass(cls):
        super().setUpClass()
        cls.endpoint = reverse("send-key-salt")
        cls.map = MerchantTestMap()
        cls.error_prefix = ":: SendKeySaltTests :: "

    @patch.object(AppLogger, "info")
    def test_successful_key_sending(self, mock_info):
        response = self.client.post(self.endpoint, self.map.get_map(["common_request_data"]))
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response.json(), self.map.get_map(["successful_response"]))
        self.assertTrue(mock_info.called)

    @patch.object(AppLogger, "info")
    @patch.object(AppLogger, "exception")
    def test_missing_merchant_id(self, mock_exception, mock_info):
        bad_data = self.map.get_map(["common_request_data"], updates={"merchant_id": ""})
        response = self.client.post(self.endpoint, bad_data)
        self.assertEqual(response.status_code, 400)
        self.assertEqual(response.json(), self.map.get_map(["error_response"]))
        self.assertTrue(mock_exception.called)

    @patch.object(Push, "push_mail")
    def test_push_notification_mock(self, mock_push):
        mock_push.return_value = True
        response = self.client.post(self.endpoint, self.map.get_map(["common_request_data"]))
        self.assertEqual(response.status_code, 200)
        mock_push.assert_called_once()

@patch.object(SomeClass, "method") dynamically replaces a method for the duration of a test.MagicMock is used to create dummy objects or simulate return values.@patch.object(Logger, "info")
def test_logs_info(self, mock_info):
    call_my_view()
    mock_info.assert_called_once()
✅ This avoids real logging and isolates the unit of work.


  A Quick Summary About Packages And Concept
✅ Django Test Framework (django.test)django.test.TestCase: Django’s built-in test class (inherits from Python’s unittest.TestCase).client = Client(): Simulates HTTP requests for views (like POST, GET, PUT).Used for integration-style tests that hit the full Django stack including URLs, middleware, views, etc.patch: A decorator/context manager to replace objects with mocks during tests.MagicMock: A flexible mock object that simulates return values, method calls, etc.Prevent hitting external APIs, file systems, DBs, or logs.Assert if external services like Push.push_mail() or PGLogger.info() were called with correct data.
Example:
@patch.object(PGLogger, "info")
def test_logging(self, mock_log):
view()
assert mock_log.called
Used to create in-memory Excel files in tests for upload scenarios.Workbook(), ws.append(...): Used to mock file content for forms, upload testing.Dynamically builds URLs from view names.Helps you avoid hardcoding endpoint paths, improving test portability.✅ django.core.files.uploadedfile.SimpleUploadedFileUsed to create mock files in memory (text, Excel, PDF).Useful for testing file upload views.Used in BaseMapFactory to return cloned test data and prevent mutation of original test dictionaries.Ensures that get_map(..., updates={}) doesn’t affect future test cases.Investing time in writing clean, isolated, and scalable unit tests pays off enormously in the long run. With a base test case, reusable factory maps, and clever mocking, your Django tests can be as maintainable as your production code.

Today I will show you how to build a tiny x and y tracker in JS
class PositionCounter {
    constructor(x = 0, y = 0) {
        this.x = x;
        this.y = y;
    }

    // Move the position by dx and dy
    move(dx, dy) {
        this.x += dx;
        this.y += dy;
        return this; // Allow method chaining
    }

    // Reset position to (0, 0)
    reset() {
        this.x = 0;
        this.y = 0;
        return this; // Allow method chaining
    }

    // Display current position
    display() {
        console.log(`Current Position: X = ${this.x}, Y = ${this.y}`);
        return this; // Allow method chaining
    }

    // Get current position as an object
    getPosition() {
        return { x: this.x, y: this.y };
    }
}

// Example usage:
const counter = new PositionCounter();

counter.move(5, 3).display();       // Move and display
counter.move(-2, 7).display();      // Move again and display
counter.reset().display();           // Reset and display

// Or get position without displaying:
const currentPos = counter.move(10, 20).getPosition();
console.log('Current position:', currentPos);


<!DOCTYPE html>
<html>
<head>
    <title>Position Counter Demo</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 20px; }
        button { margin: 5px; padding: 8px 12px; }
        #output { margin-top: 20px; padding: 10px; border: 1px solid #ccc; }
    </style>
</head>
<body>
    <h1>Position Counter</h1>
    <div>
        <button onclick="move(1, 0)">Move Right (+X)</button>
        <button onclick="move(-1, 0)">Move Left (-X)</button>
        <button onclick="move(0, 1)">Move Down (+Y)</button>
        <button onclick="move(0, -1)">Move Up (-Y)</button>
        <button onclick="reset()">Reset</button>
    </div>
    <div id="output">Position: X=0, Y=0</div>

    <script>
        const counter = new PositionCounter();
        const output = document.getElementById('output');

        function updateDisplay() {
            output.textContent = `Position: X=${counter.x}, Y=${counter.y}`;
        }

        function move(dx, dy) {
            counter.move(dx, dy);
            updateDisplay();
        }

        function reset() {
            counter.reset();
            updateDisplay();
        }

        // The PositionCounter class from above would go here
        class PositionCounter {
            constructor(x = 0, y = 0) {
                this.x = x;
                this.y = y;
            }

            move(dx, dy) {
                this.x += dx;
                this.y += dy;
                return this;
            }

            reset() {
                this.x = 0;
                this.y = 0;
                return this;
            }
        }
    </script>
</body>
</html>

Welcome to  of our FastAPI journey! Yesterday, we explored how to use Request Bodies and Pydantic to validate data like a pro.Today, we step into the powerful world of  — and why FastAPI’s  makes our code cleaner, reusable, and more secure.


  🧠 What Is Dependency Injection (DI)?
Imagine you're building an app where every route requires , or , or even a .Instead of repeating the same logic in every route, you can  it once using  — and FastAPI handles it for you!


  🎯 Real-World Analogy:  is Your Personal Assistant
Let’s say you run a restaurant. Instead of you greeting customers, validating reservations, and serving them every time…You  those tasks to trusted staff — that’s Dependency Injection!Your function = the restaurantThe  function = your assistant (API key checker, paginator, etc.)FastAPI = your efficient manager


  🔧 Step-by-Step: Basic Dependency Injection



  📁 Create a file called from fastapi import FastAPI, Depends

app = FastAPI()

# Step 1: Create a dependency function
def say_hello():
    return "Hello from a dependency!"

# Step 2: Inject it using Depends
@app.get("/")
def read_root(greeting: str = Depends(say_hello)):
    return {"message": greeting}



  🖥️ Start the FastAPI server:
uvicorn di_app:app --host 0.0.0.0 --reload --port 9005
✅ Try it — FastAPI will automatically call  and inject its return value.


  🔐 Add Security – API Key Validation
Let’s say every route must check if a valid API key is present in the request headers.We can use FastAPI’s  along with  to inject and validate the API key for any endpoint.Here's how you define a reusable  to validate the API key:from fastapi import Header, HTTPException

API_KEY = "mysecret"

def verify_api_key(x_api_key: str = Header(...)):
    if x_api_key != API_KEY:
        raise HTTPException(status_code=401, detail="Invalid API Key")

@app.get("/secure")
def secure_data(_ = Depends(verify_api_key)):
    return {"data": "Top secret info!"}



  🖥️ Start the FastAPI server:
uvicorn di_app:app --host 0.0.0.0 --reload --port 9005



  🔄 Reusable Pagination Logic
Sometimes, you want to apply the same pagination logic to multiple endpoints (e.g.,  and  query parameters).Instead of repeating the parameters in every route, you can use  to inject reusable logic — keeping your code clean and DRY.


  ✅ Define a Reusable Pagination Dependency
from fastapi import Depends, FastAPI

app = FastAPI()

def pagination(skip: int = 0, limit: int = 10):
    return {"skip": skip, "limit": limit}

@app.get("/items")
def get_items(paging: dict = Depends(pagination)):
    return {"pagination": paging}

 is a simple function that takes  and  as  with default values. injects those values into your route as a .You can reuse  in  that supports pagination — no duplication!


  🖥️ Start the FastAPI server:
uvicorn di_app:app --host 0.0.0.0 --reload --port 9005
This pattern is perfect for **list-based APIs like , , , and more — where consistent pagination behavior is needed.**Inject shared logic (API key, DB session, etc.)Use  +  for auth checksQuery params as dependenciesReuse pagination, filtering, etc. in multiple routesDependency Function ExampleReuse  and  parametersInject DB connection using SQLAlchemyGet current user from JWT or sessionHey there! I’m , an AWS Community Builder and passionate cloud-native enthusiast who loves building scalable backend systems and sharing knowledge with the community.


  💬 Share Your Thoughts – I'd Love Your Feedback!
If you enjoyed today's post or learned something new, I'd truly appreciate it if you leave a comment or share your thoughts 👇Your feedback, questions, or even a quick  keeps me motivated to continue this journey and share more in the upcoming  posts.✅ What did you find most helpful?Anything you'd like explained in the next part?Suggestions for improvement? I’m all ears! 🙌Let’s grow and learn together — one FastAPI day at a time 🚀

Recordings of business meetings, interviews, and customer interactions have become essential for preserving important information. However, transcribing and summarizing these recordings manually is often time-consuming and labor-intensive. With the progress in generative AI and automatic speech recognition (ASR), automated solutions have emerged to make this process faster and more efficient.Protecting personally identifiable information (PII) is a vital aspect of data security, driven by both ethical responsibilities and legal requirements. In this post, we demonstrate how to use the Open AI Whisper foundation model (FM) Whisper Large V3 Turbo, available in Amazon Bedrock Marketplace, which offers access to over 140 models through a dedicated offering, to produce near real-time transcription. These transcriptions are then processed by Amazon Bedrock for summarization and redaction of sensitive information.In this post, we walk through an end-to-end architecture that combines a React-based frontend with Amazon Bedrock, AWS Lambda, and AWS Step Functions to orchestrate the workflow, facilitating seamless integration and processing.The solution highlights the power of integrating serverless technologies with generative AI to automate and scale content processing workflows. The user journey begins with uploading a recording through a React frontend application, hosted on Amazon CloudFront and backed by Amazon Simple Storage Service (Amazon S3) and Amazon API Gateway. When the file is uploaded, it triggers a Step Functions state machine that orchestrates the core processing steps, using AI models and Lambda functions for seamless data flow and transformation. The following diagram illustrates the solution architecture.The workflow consists of the following steps:The React application is hosted in an S3 bucket and served to users through CloudFront for fast, global access. API Gateway handles interactions between the frontend and backend services.Users upload audio or video files directly from the app. These recordings are stored in a designated S3 bucket for processing.An Amazon EventBridge rule detects the S3 upload event and triggers the Step Functions state machine, initiating the AI-powered processing pipeline.The state machine performs audio transcription, summarization, and redaction by orchestrating multiple Amazon Bedrock models in sequence. It uses Whisper for transcription, Claude for summarization, and Guardrails to redact sensitive data.The redacted summary is returned to the frontend application and displayed to the user.The following diagram illustrates the state machine workflow.The Step Functions state machine orchestrates a series of tasks to transcribe, summarize, and redact sensitive information from uploaded audio/video recordings:A Lambda function is triggered to gather input details (for example, Amazon S3 object path, metadata) and prepare the payload for transcription.The payload is sent to the OpenAI Whisper Large V3 Turbo model through the Amazon Bedrock Marketplace to generate a near real-time transcription of the recording.The raw transcript is passed to Anthropic’s Claude Sonnet 3.5 through Amazon Bedrock, which produces a concise and coherent summary of the conversation or content.A second Lambda function validates and forwards the summary to the redaction step.The summary is processed through Amazon Bedrock Guardrails, which automatically redacts PII and other sensitive data.The redacted summary is stored or returned to the frontend application through an API, where it is displayed to the user.Before you start, make sure that you have the following prerequisites in place:Create a guardrail in the Amazon Bedrock consoleEnable PII detection and handlingAdd the relevant PII types, such as: 
  Other sensitive personal informationAfter you deploy the guardrail, note the Amazon Resource Name (ARN), and you will be using this when deploys the model.Complete the following steps to deploy the Whisper Large V3 Turbo model:On the Amazon Bedrock console, choose under in the navigation pane.Search for and choose .On the options menu (three dots), choose .Modify the endpoint name, number of instances, and instance type to suit your specific use case. For this post, we use the default settings.Modify the  section to suit your use case. For this post, we use the default settings.You can choose  in the navigation pane, and in the  section, you can see the endpoint status as . Wait for the endpoint to finish deployment and the status to change to , then copy the Endpoint Name, and you will be using this when deploying theDeploy the solution infrastructureIn the GitHub repo, follow the instructions in the README file to clone the repository, then deploy the frontend and backend infrastructure.We use the AWS Cloud Development Kit (AWS CDK) to define and deploy the infrastructure. The AWS CDK code deploys the following resources:React frontend applicationS3 buckets for storing uploads and processed resultsStep Functions state machine with Lambda functions for audio processing and PII redactionAPI Gateway endpoints for handling requestsIAM roles and policies for secure accessCloudFront distribution for hosting the frontendThe backend is composed of a sequence of Lambda functions, each handling a specific stage of the audio processing pipeline: – Receives audio files and stores them in Amazon S3Transcription with Whisper – Converts speech to text using the Whisper model – Differentiates and labels individual speakers within the audioSummarization using Amazon Bedrock – Extracts and summarizes key points from the transcript – Uses Amazon Bedrock Guardrails to remove sensitive information for privacy complianceLet’s examine some of the key components:The transcription Lambda function uses the Whisper model to convert audio files to text:def transcribe_with_whisper(audio_chunk, endpoint_name):
    # Convert audio to hex string format
    hex_audio = audio_chunk.hex()

    # Create payload for Whisper model
    payload = {
        "audio_input": hex_audio,
        "language": "english",
        "task": "transcribe",
        "top_p": 0.9
    }

    # Invoke the SageMaker endpoint running Whisper
    response = sagemaker_runtime.invoke_endpoint(
        EndpointName=endpoint_name,
        ContentType='application/json',
        Body=json.dumps(payload)
    )

    # Parse the transcription response
    response_body = json.loads(response['Body'].read().decode('utf-8'))
    transcription_text = response_body['text']

    return transcription_text
We use Amazon Bedrock to generate concise summaries from the transcriptions:def generate_summary(transcription):
    # Format the prompt with the transcription
    prompt = f"{transcription}\n\nGive me the summary, speakers, key discussions, and action items with owners"

    # Call Bedrock for summarization
    response = bedrock_runtime.invoke_model(
        modelId="anthropic.claude-3-5-sonnet-20240620-v1:0",
        body=json.dumps({
            "prompt": prompt,
            "max_tokens_to_sample": 4096,
            "temperature": 0.7,
            "top_p": 0.9,
        })
    )

    # Extract and return the summary
    result = json.loads(response.get('body').read())
    return result.get('completion')A critical component of our solution is the automatic redaction of PII. We implemented this using Amazon Bedrock Guardrails to support compliance with privacy regulations:def apply_guardrail(bedrock_runtime, content, guardrail_id):
# Format content according to API requirements
formatted_content = [{"text": {"text": content}}]

# Call the guardrail API
response = bedrock_runtime.apply_guardrail(
guardrailIdentifier=guardrail_id,
guardrailVersion="DRAFT",
source="OUTPUT",  # Using OUTPUT parameter for proper flow
content=formatted_content
)

# Extract redacted text from response
if 'action' in response and response['action'] == 'GUARDRAIL_INTERVENED':
if len(response['outputs']) > 0:
output = response['outputs'][0]
if 'text' in output and isinstance(output['text'], str):
return output['text']

# Return original content if redaction fails
return contentWhen PII is detected, it’s replaced with type indicators (for example, {PHONE} or {EMAIL}), making sure that summaries remain informative while protecting sensitive data.To manage the complex processing pipeline, we use Step Functions to orchestrate the Lambda functions:{
"Comment": "Audio Summarization Workflow",
"StartAt": "TranscribeAudio",
"States": {
"TranscribeAudio": {
"Type": "Task",
"Resource": "arn:aws:states:::lambda:invoke",
"Parameters": {
"FunctionName": "WhisperTranscriptionFunction",
"Payload": {
"bucket": "$.bucket",
"key": "$.key"
}
},
"Next": "IdentifySpeakers"
},
"IdentifySpeakers": {
"Type": "Task",
"Resource": "arn:aws:states:::lambda:invoke",
"Parameters": {
"FunctionName": "SpeakerIdentificationFunction",
"Payload": {
"Transcription.$": "$.Payload"
}
},
"Next": "GenerateSummary"
},
"GenerateSummary": {
"Type": "Task",
"Resource": "arn:aws:states:::lambda:invoke",
"Parameters": {
"FunctionName": "BedrockSummaryFunction",
"Payload": {
"SpeakerIdentification.$": "$.Payload"
}
},
"End": true
}
}
}This workflow makes sure each step completes successfully before proceeding to the next, with automatic error handling and retry logic built in.After you have successfully completed the deployment, you can use the CloudFront URL to test the solution functionality.Security is a critical aspect of this solution, and we’ve implemented several best practices to support data protection and compliance: – Automatically redact PII to protect user privacy.Fine-Grained IAM Permissions – Apply the principle of least privilege across AWS services and resources.Amazon S3 access controls – Use strict bucket policies to limit access to authorized users and roles. – Secure API endpoints using Amazon Cognito for user authentication (optional but recommended). – Enforce HTTPS and apply modern TLS protocols to facilitate secure content delivery.Amazon Bedrock data security – Amazon Bedrock (including Amazon Bedrock Marketplace) protects customer data and does not send data to providers or train using customer data. This makes sure your proprietary information remains secure when using AI capabilities.To prevent unnecessary charges, make sure to delete the resources provisioned for this solution when you’re done:Delete the Amazon Bedrock guardrail: 
  On the Amazon Bedrock console, in the navigation menu, choose .Choose your guardrail, then choose .Delete the Whisper Large V3 Turbo model deployed through the Amazon Bedrock Marketplace: 
  On the Amazon Bedrock console, choose in the navigation pane.In the  section, select the deployed endpoint and choose .Delete the AWS CDK stack by running the command , which deletes the AWS infrastructure.This serverless audio summarization solution demonstrates the benefits of combining AWS services to create a sophisticated, secure, and scalable application. By using Amazon Bedrock for AI capabilities, Lambda for serverless processing, and CloudFront for content delivery, we’ve built a solution that can handle large volumes of audio content efficiently while helping you align with security best practices.The automatic PII redaction feature supports compliance with privacy regulations, making this solution well-suited for regulated industries such as healthcare, finance, and legal services where data security is paramount. To get started, deploy this architecture within your AWS environment to accelerate your audio processing workflows. is a Senior Solutions Architect for Strategic Accounts at Amazon Web Services, with years of experience across enterprises, startups, and professional services. Currently, she helps customers build cloud solutions and drives GenAI adoption to cloud. Previously, Kaiyin worked in the Smart Home domain, assisting customers in integrating voice and IoT technologies. is a Solutions Architect with AWS covering Strategic accounts.  He thrives on resolving complex technical issues to overcome customer hurdles. Outside of work, he cherishes spending time with his family and fostering inquisitiveness in his children.

GPUs are a precious resource; they are both short in supply and much more costly than traditional CPUs. They are also highly adaptable to many different use cases. Organizations building or adopting generative AI use GPUs to run simulations, run inference (both for internal or external usage), build agentic workloads, and run data scientists’ experiments. The workloads range from ephemeral single-GPU experiments run by scientists to long multi-node continuous pre-training runs. Many organizations need to share a centralized, high-performance GPU computing infrastructure across different teams, business units, or accounts within their organization. With this infrastructure, they can maximize the utilization of expensive accelerated computing resources like GPUs, rather than having siloed infrastructure that might be underutilized. Organizations also use multiple AWS accounts for their users. Larger enterprises might want to separate different business units, teams, or environments (production, staging, development) into different AWS accounts. This provides more granular control and isolation between these different parts of the organization. It also makes it straightforward to track and allocate cloud costs to the appropriate teams or business units for better financial oversight.The specific reasons and setup can vary depending on the size, structure, and requirements of the enterprise. But in general, a multi-account strategy provides greater flexibility, security, and manageability for large-scale cloud deployments. In this post, we discuss how an enterprise with multiple accounts can access a shared Amazon SageMaker HyperPod cluster for running their heterogenous workloads. We use SageMaker HyperPod task governance to enable this feature.SageMaker HyperPod task governance streamlines resource allocation and provides cluster administrators the capability to set up policies to maximize compute utilization in a cluster. Task governance can be used to create distinct teams with their own unique namespace, compute quotas, and borrowing limits. In a multi-account setting, you can restrict which accounts have access to which team’s compute quota using role-based access control.In this post, we describe the settings required to set up multi-account access for SageMaker HyperPod clusters orchestrated by Amazon Elastic Kubernetes Service (Amazon EKS) and how to use SageMaker HyperPod task governance to allocate accelerated compute to multiple teams in different accounts.The following diagram illustrates the solution architecture.In this architecture, one organization is splitting resources across a few accounts. Account A hosts the SageMaker HyperPod cluster. Account B is where the data scientists reside. Account C is where the data is prepared and stored for training usage. In the following sections, we demonstrate how to set up multi-account access so that data scientists in Account B can train a model on Account A’s SageMaker HyperPod and EKS cluster, using the preprocessed data stored in Account C. We break down this setup in two sections: cross-account access for data scientists and cross-account access for prepared data.Cross-account access for data scientistsWhen you create a compute allocation with SageMaker HyperPod task governance, your EKS cluster creates a unique Kubernetes namespace per team. For this walkthrough, we create an AWS Identity and Access Management (IAM) role per team, called , that are then scoped access only to the team’s task governance-generated namespace in the shared EKS cluster. Role-based access control is how we make sure the data science members of Team A will not be able to submit tasks on behalf of Team B.To access Account A’s EKS cluster as a user in Account B, you will need to assume a cluster access role in Account A. The cluster access role will have only the needed permissions for data scientists to access the EKS cluster. For an example of IAM roles for data scientists using SageMaker HyperPod, see IAM users for scientists.Next, you will need to assume the cluster access role from a role in Account B. The cluster access role in Account A will then need to have a trust policy for the data scientist role in Account B. The data scientist role is the role in account B that will be used to assume the cluster access role in Account A. The following code is an example of the policy statement for the data scientist role so that it can assume the cluster access role in Account A:{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": "sts:AssumeRole",
      "Resource": "arn:aws:iam::XXXXXXXXXXAAA:role/ClusterAccessRole"
    }
  ]
}The following code is an example of the trust policy for the cluster access role so that it allows the data scientist role to assume it:{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::XXXXXXXXXXBBB:role/DataScientistRole"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}The final step is to create an access entry for the team’s cluster access role in the EKS cluster. This access entry should also have an access policy, such as EKSEditPolicy, that is scoped to the namespace of the team. This makes sure that Team A users in Account B can’t launch tasks outside of their assigned namespace. You can also optionally set up custom role-based access control; see Setting up Kubernetes role-based access control for more information.For users in Account B, you can repeat the same setup for each team. You must create a unique cluster access role for each team to align the access role for the team with their associated namespace. To summarize, we use two different IAM roles: – The role in Account B used to assume the cluster access role in Account A. This role just needs to be able to assume the cluster access role.Cross-account access to prepared dataIn this section, we demonstrate how to set up EKS Pod Identity and S3 Access Points so that pods running training tasks in Account A’s EKS cluster have access to data stored in Account C. EKS Pod Identity allow you to map an IAM role to a service account in a namespace. If a pod uses the service account that has this association, then Amazon EKS will set the environment variables in the containers of the pod.S3 Access Points are named network endpoints that simplify data access for shared datasets in S3 buckets. They act as a way to grant fine-grained access control to specific users or applications accessing a shared dataset within an S3 bucket, without requiring those users or applications to have full access to the entire bucket. Permissions to the access point is granted through S3 access point policies. Each S3 Access Point is configured with an access policy specific to a use case or application. Since the HyperPod cluster in this blog post can be used by multiple teams, each team could have its own S3 access point and access point policy.In Account A, create an IAM Role that contains S3 permissions (such as  and  to the access point resource) and has a trust relationship with Pod Identity; this will be your Data Access Role. Below is an example of a trust policy.{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "AllowEksAuthToAssumeRoleForPodIdentity",
      "Effect": "Allow",
      "Principal": {
        "Service": "pods.eks.amazonaws.com"
      },
      "Action": [
        "sts:AssumeRole",
        "sts:TagSession"
      ]
    }
  ]
}
Next, configure your S3 access point to allow access to the role created in step 1. This is an example access point policy that gives Account A permission to access points in account C.{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::<Account-A-ID>:role/<Data-Access-Role-Name>"
      },
      "Action": [
        "s3:ListBucket",
        "s3:GetObject"
      ],
      "Resource": [
        "arn:aws:s3:<Region>:<Account-C-ID>:accesspoint/<Access-Point-Name>",
        "arn:aws:s3:<Region>:<Account-C-ID>:accesspoint/<Access-Point-Name>/object/*"
      ]
    }
  ]
}
Ensure your S3 bucket policy is updated to allow Account A access. This is an example S3 bucket policy:{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": "*",
      "Action": [
        "s3:GetObject",
        "s3:ListBucket"
      ],
      "Resource": [
        "arn:aws:s3:::<bucket-name>",
        "arn:aws:s3:::<bucket-name>/*"
      ],
      "Condition": {
        "StringEquals": {
          "s3:DataAccessPointAccount": "<Account-C-ID>"
        }
      }
    }
  ]
}
In Account A, create a pod identity association for your EKS cluster using the AWS CLI.aws eks create-pod-identity-association 
--cluster-name <EKS-Cluster-Name> 
--role-arn arn:aws:iam::<Account-A-ID>:role/<Data-Access-Role-Name> 
--namespace hyperpod-ns-eng 
--service-account my-service-accountPods accessing cross-account S3 buckets will need the service account name referenced in their pod specification.You can test cross-account data access by spinning up a test pod and the executing into the pod to run Amazon S3 commands:kubectl exec -it aws-test -n hyperpod-ns-team-a -- aws s3 ls s3://<access-point>This example shows creating a single data access role for a single team. For multiple teams, use a namespace-specific ServiceAccount with its own data access role to help prevent overlapping resource access across teams. You can also configure cross-account Amazon S3 access for an Amazon FSx for Lustre file system in Account A, as described in Use Amazon FSx for Lustre to share Amazon S3 data across accounts. FSx for Lustre and Amazon S3 will need to be in the same AWS Region, and the FSx for Lustre file system will need to be in the same Availability Zone as your SageMaker HyperPod cluster.In this post, we provided guidance on how to set up cross-account access to data scientists accessing a centralized SageMaker HyperPod cluster orchestrated by Amazon EKS. In addition, we covered how to provide Amazon S3 data access from one account to an EKS cluster in another account. With SageMaker HyperPod task governance, you can restrict access and compute allocation to specific teams. This architecture can be used at scale by organizations wanting to share a large compute cluster across accounts within their organization. To get started with SageMaker HyperPod task governance, refer to the Amazon EKS Support in Amazon SageMaker HyperPod workshop and SageMaker HyperPod task governance documentation.Nisha Nadkarni is a Senior GenAI Specialist Solutions Architect at AWS, where she guides companies through best practices when deploying large scale distributed training and inference on AWS. Prior to her current role, she spent several years at AWS focused on helping emerging GenAI startups develop models from ideation to production.Anoop Saha is a Sr GTM Specialist at Amazon Web Services (AWS) focusing on generative AI model training and inference. He partners with top frontier model builders, strategic customers, and AWS service teams to enable distributed training and inference at scale on AWS and lead joint GTM motions. Before AWS, Anoop held several leadership roles at startups and large corporations, primarily focusing on silicon and system architecture of AI infrastructure.Kareem Syed-Mohammed is a Product Manager at AWS. He is focused on compute optimization and cost governance. Prior to this, at Amazon QuickSight, he led embedded analytics, and developer experience. In addition to QuickSight, he has been with AWS Marketplace and Amazon retail as a Product Manager. Kareem started his career as a developer for call center technologies, Local Expert and Ads for Expedia, and management consultant at McKinsey.Rajesh Ramchander is a Principal ML Engineer in Professional Services at AWS. He helps customers at various stages in their AI/ML and GenAI journey, from those that are just getting started all the way to those that are leading their business with an AI-first strategy.

When building a command line application (CLI), developers use CLI Option Prompt [typer]. However, if you need more interactivity and simplicity on the terminal, you are likely to use . Like every library in development, we have to pause and consider: How much control are we really giving up when we depend on typer.prompt() to make our CLI more interactive?I have been building a CLI application to better track and predict cervical cancer in women. The Typer library was great in creating visually-appealing output on the terminal, until I needed to enable a filtering option. I wanted to give my user the option of filtering health profiles based on a single ID or leave blank to provide an unfiltered output. However, in my testing, I realized that by pressing ENTER without inputting any value, typer.prompt() re-prompted me to input a value, instead of accepting an empty string. I got into a loop of prompts.Despite expecting user_id to be "", the prompt came up again!As usual, I thought that my logic was wrong, so I went back different 'best practices' in CLI:I began by guarding user_id by changing from: user_id = typer.prompt("Filter by user ID (or leave blank)").strip() or None list_all_profiles(user_id=int(user_id) if user_id else None)
user_input = typer.prompt("Filter by user ID (or leave blank)").strip() user_id = int(user_input) if user_input else None list_all_profiles(user_id=user_id) After option 1 failed, I tried added isdigit() to eliminate catch non-numeric issues, but that failed, and the loop continued. Next, I wrapped the code in a try-except block with return values to prevent re-looping due to unexpected errors and value-errors, but I kept incurring an endless loop of re-prompting. Until I came across an 8-year old Stack Overflow issue [Stack Overflow] about Python's Click limit with empty prompts. While the issue had Click's syntax, I decided to replicate it on typer.prompt:elif choice == '2': try: typer.secho("Leave filters blank to view all profiles.", fg=typer.colors.BRIGHT_BLACK)
user_input = typer.prompt("Filter by user ID (or leave blank)", default="").strip() user_id = int(user_input) if user_input else None list_all_profiles(user_id=user_id)
except ValueError: typer.secho("Invalid filter values. Please use numbers or leave blank.", fg=typer.colors.RED)
except Exception as e: typer.secho(f"Unexpected error: {e}", fg=typer.colors.RED)
Although this Prompt behavior in Typer is logical once comprehended, it is not obvious, especially for beginners. Therefore, the Prompt's interactivity would improve by:Typer providing advanced documentation on prompt() behavior in different scenarios.Providing alternatives, especially when defaults are not set. Clear warnings or handling of empty inputs in CLIs. Are you exploring CLIs and Typer? Have you ran into this challenge and have ways of enhancing prompt()? Consider visiting and contributing to their GitHub repository [fastApi/typer].Like any other bug, this prompt() problem reminded me of how all libraries have simple tools that while they simplify our codes, they demand an understanding of underlying principles.I hope my journey with Typer and empty inputs saves someone and builds to the tool's best practices.

As organizations look to incorporate AI capabilities into their applications, large language models (LLMs) have emerged as powerful tools for natural language processing tasks. Amazon SageMaker AI provides a fully managed service for deploying these machine learning (ML) models with multiple inference options, allowing organizations to optimize for cost, latency, and throughput. AWS has always provided customers with choice. That includes model choice, hardware choice, and tooling choice. In terms of hardware choice, in addition to NVIDIA GPUs and AWS custom AI chips, CPU-based instances represent (thanks to the latest innovations in CPU hardware) an additional choice for customers who want to run generative AI inference, like hosting small language models and asynchronous agents.Traditional LLMs with billions of parameters require significant computational resources. For example, a 7-billion-parameter model like Meta Llama 7B at BFloat16 (2 bytes per parameter) typically needs around 14 GB of GPU memory to store the model weights—the total GPU memory requirement is usually 3–4 times bigger at long sequence lengths. However, recent developments in model quantization and knowledge distillation have made it possible to run smaller, efficient language models on CPU infrastructure. Although these models might not match the capabilities of the largest LLMs, they offer a practical alternative for many real-world applications where cost optimization is crucial.In this post, we demonstrate how to deploy a small language model on SageMaker AI by extending our pre-built containers to be compatible with AWS Graviton instances. We first provide an overview of the solution, and then provide detailed implementation steps to help you get started. You can find the example notebook in the GitHub repo.Our solution uses SageMaker AI with Graviton3 processors to run small language models cost-efficiently. The key components include:SageMaker AI hosted endpoints for model servingGraviton3 based instances (ml.c7g series) for computationA container installed with llama.cpp for the Graviton optimized inferencePre-quantized GGUF format modelsGraviton processors, which are specifically designed for cloud workloads, provide an optimal platform for running these quantized models. Graviton3 based instances can deliver up to 50% better price-performance compared to traditional x86-based CPU instances for ML inference workloads.We have used Llama.cpp as the inference framework. It supports quantized general matrix multiply-add (GEMM) kernels for faster inference and reduced memory use. The quantized GEMM kernels are optimized for Graviton processors using Arm Neon and SVE-based matrix multiply-accumulate (MMLA) instructions.Llama.cpp uses GGUF, a special binary format for storing the model and metadata. GGUF format is optimized for quick loading and saving of models, making it highly efficient for inference purposes. Existing models need to be converted to GGUF format before they can be used for the inference. You can find most of popular GGUF format models from the following Hugging Face repo, or you can also convert your model to GGUF format using the following tool.The following diagram illustrates the solution architecture.To deploy your model on SageMaker with Graviton, you will need to complete the following steps:Create a Docker container compatible with ARM64 architecture.Prepare your model and inference code.Create a SageMaker model and deploy to an endpoint with a Graviton instance.We walk through these steps in the following sections.To implement this solution, you need an AWS account with the necessary permissions.Create a Docker container compatible with ARM64 architectureLet’s first review how SageMaker AI works with Docker containers. Basically, by packaging an algorithm in a container, you can bring almost any code to the SageMaker environment, regardless of programming language, environment, framework, or dependencies. For more information and an example of how to build your own Docker container for training and inference with SageMaker AI, see Build your own algorithm container.You can also extend a pre-built container to accommodate your needs. By extending a pre-built image, you can use the included deep learning libraries and settings without having to create an image from scratch. You can extend the container to add libraries, modify settings, and install additional dependencies. For a list of available pre-built containers, refer to the following GitHub repo. In this example, we show how to package a pre-built PyTorch container that supports Graviton instances, extending the SageMaker PyTorch container, with a Python example that works with the DeepSeek distilled model.Firstly, let’s review how SageMaker AI runs your Docker container. Typically, you specify a program (such as a script) as an ENTRYPOINT in the Dockerfile; that program will run at startup and decide what to do. The original ENTRYPOINT specified within the SageMaker PyTorch is listed in the GitHub repo. To learn how to extend our pre-built container for model training, refer to Extend a Pre-built Container. In this example, we only use the inference container.Running your container during hostingHosting has a very different model than training because hosting is responding to inference requests that come in through HTTP. At the time of writing, the SageMaker PyTorch containers use our TorchServe to provide robust and scalable serving of inference requests, as illustrated in the following diagram.SageMaker uses two URLs in the container: receives GET requests from the infrastructure. Your program returns 200 if the container is up and accepting requests. is the endpoint that receives client inference POST The format of the request and the response is up to the algorithm. If the client supplied ContentType and Accept headers, these are passed in as well.The container has the model files in the same place that they were written to during training:Custom files available to build the container used in this exampleThe container directory has all the components you need to extend the SageMaker PyTorch container to use as a sample algorithm:Let’s discuss each of these in turn:Dockerfile describes how to build your Docker container image for inference.sh is a script that uses the Dockerfile to build your container images and then pushes it to Amazon Elastic Container Registry (Amazon ECR). We invoke the commands directly later in this notebook, but you can copy and run the script for your own algorithms. To build a Graviton compatible Docker image, we launch a ARM64 architecture-based AWS CodeBuild environment and build the Docker image from the Dockerfile, then push the Docker image to the ECR repo. Refer to the script for more details.code is the directory that contains our user code to be invoked.In this application, we install or update a few libraries for running Llama.cpp in Python. We put the following files in the container:py is the program that implements our inference code (used only for the inference container)txt is the text file that contains additional Python packages that will be installed during deployment timeThe Dockerfile describes the image that we want to build. We start from the SageMaker PyTorch image as the base inference one. The SageMaker PyTorch ECR image that supports Graviton in this case would be:FROM 763104351884.dkr.ecr.{region}.amazonaws.com/pytorch-inference-arm64:2.5.1-cpu-py311-ubuntu22.04-sagemakerNext, we install the required additional libraries and add the code that implements our specific algorithm to the container, and set up the right environment for it to run under. We recommend configuring the following optimizations for Graviton in the Dockerfile and the inference code for better performance:In the Dockerfile, add compile flags like  when installing the llama.cpp Python package. The combination of these flags can lead to code optimized for the specific ARM architecture of Graviton and parallel execution that takes full advantage of the multi-core nature of Graviton processors.Set  to the number of vCPUs explicitly in the inference code to use all cores (vCPUs) on Graviton.Use quantized  models, which minimizes accuracy loss while aligning well with CPU architectures, improving CPU inference performance by reducing memory footprint and enhancing cache utilization. For information on how to quantize models, refer to the llama.cpp README.The  script describes how to automate the setup of a CodeBuild project specifically designed for building Docker images on ARM64 architecture. It sets up essential configuration variables; creates necessary AWS Identity and Access Management (IAM) roles with appropriate permissions for Amazon CloudWatch Logs, Amazon Simple Storage Service (Amazon S3), and Amazon ECR access; and establishes a CodeBuild project using an ARM-based container environment. The script includes functions to check for project existence and wait for project readiness, while configuring the build environment with required variables and permissions for building and pushing Docker images, particularly for the llama.cpp inference code.Prepare your model and inference codeGiven the use of a pre-built SageMaker PyTorch container, we can simply write an inference script that defines the following functions to handle input data deserialization, model loading, and prediction: reads the content of an existing model weights directory from the `/opt/ml/model` or uses the  parameter passed to the function, which is a directory where the model is saved is used to format the data received from a request made to the endpoint calls the output of  to run inference on the output of  optionally serializes predictions from  to the format that can be transferred back through HTTP packages, such as JSONNormally, you would compress model files into a TAR file; however, this can cause startup time to take longer due to having to download and untar large files. To improve startup times, SageMaker AI supports use of uncompressed files. This removes the need to untar large files. In this example, we upload all the files to an S3 prefix and then pass the location into the model with “CompressionType”: “None”.Create a SageMaker model and deploy to an endpoint with a Graviton instanceNow we can use the PyTorchModel class provided by SageMaker Python SDK to create a PyTorch SageMaker model that can be deployed to a SageMaker endpoint:pytorch_model = PyTorchModel(model_data={
                                "S3DataSource": {
                                    "S3Uri": model_path,
                                    "S3DataType": "S3Prefix",
                                    "CompressionType": "None",
                                }
                            },
                             role=role,
                             env={
                                 'MODEL_FILE_GGUF':file_name
                             },
                             image_uri=f"{sagemaker_session.account_id()}.dkr.ecr.{region}.amazonaws.com/llama-cpp-python:latest",
                             model_server_workers=2
)

predictor = pytorch_model.deploy(instance_type='ml.c7g.12xlarge', initial_instance_count=1)TorchServe runs multiple workers on the container for inference, where each worker hosts a copy of the model.  controls the number of workers that TorchServe will run by configuring the ‘SAGEMAKER_MODEL_SERVER_WORKERS‘ environment variable. Therefore, we recommend using a small number for the model server workers.Then we can invoke the endpoint with either the predictor object returned by the deploy function or use a low-level Boto3 API as follows:client = boto3.client('sagemaker-runtime')

response = client.invoke_endpoint(
    EndpointName=endpoint_name,
    ContentType="application/json",
    Body=json.dumps(prompt)
)
print(response['Body'].read().decode("utf-8"))Performance optimization discussionWhen you’re happy with a specific model, or a quantized version of it, for your use case, you can start tuning your compute capacity to serve your users at scale. When running LLM inference, we look at two main metrics to evaluate performance: latency and throughput. Tools like LLMPerf enable measuring these metrics on SageMaker AI endpoints. – Represents the per-user experience by measuring the time needed to process a user request or prompt – Represents the overall token throughput, measured in tokens per seconds, aggregated for user requestsWhen serving users in parallel, batching those parallel requests together can improve throughput and increase compute utilization by moving the multiple inputs together with the model weights from the host memory to the CPU in order to generate the output tokens. Model serving backends like vLLM and Llama.cpp support continuous batching, which automatically adds new requests to the existing batch, replacing old requests that finished their token generation phases. However, configuring higher batch sizes comes at the expense of per-user latency, so you should tune the batch size for the best latency-throughput combination on the ML instance you’re using on SageMaker AI. In addition to batching, using prompt or prefix caching to reuse the precomputed attention matrices in similar subsequent requests can further boost latency.When you find the optimal batch size for your use case, you can tune your endpoint’s auto scaling policy to serve your users at scale using an endpoint exposing multiple CPU-based ML instances, which scales according the application load. Let’s say you are able to successfully serve 10 requests users in parallel with one ML instance. You can scale out by increasing the number of instances to reach the number of instances needed to serve your target number of users—for example, you would need 10 instances to serve 100 users in parallel.To avoid unwanted charges, clean up the resources you created as part of this solution if you no longer need it.SageMaker AI with Graviton processors offers a compelling solution for organizations looking to deploy AI capabilities cost-effectively. By using CPU-based inference with quantized models, this approach delivers up to 50% cost savings compared to traditional deployments while maintaining robust performance for many real-world applications. The combination of simplified operations through the fully managed SageMaker infrastructure, flexible auto scaling with zero-cost downtime, and enhanced deployment speed with container caching technology makes it an ideal platform for production AI workloads.To get started, explore our sample notebooks on GitHub and reference documentation to evaluate whether CPU-based inference suits your use case. You can also refer to the AWS Graviton Technical Guide, which provides the list of optimized libraries and best practices that can help you achieve cost benefits with Graviton instances across different workloads. is an Efficient Compute Specialist Solutions Architect at AWS based in Sydney, Australia. He helps customers optimize their cloud infrastructure by leveraging AWS’s silicon innovations, including AWS Graviton processors and AWS Neuron technology. Vincent’s expertise lies in developing AI/ML applications that harness the power of open-source software combined with AWS’s specialized AI chips, enabling organizations to achieve better performance and cost-efficiency in their cloud deployments. is a Cloud Support Engineer in the SageMaker, Vision & Other team at AWS, based in Sydney, Australia. He supports customers using many AI/ML services on AWS with expertise in working with Amazon SageMaker. Outside of work, he enjoys spending time with friends and family as well as learning about different technologies. PhD, is a Senior Generative AI Specialist Solutions Architect at AWS based in Sydney, Australia, where her focus is on working with customers to build solutions leveraging state-of-the-art AI and machine learning tools. She has been actively involved in multiple Generative AI initiatives across APJ, harnessing the power of Large Language Models (LLMs). Prior to joining AWS, Dr. Li held data science roles in the financial and retail industries.Oussama Maxime Kandakji is a Senior AI/ML Solutions Architect at AWS focusing on AI Inference and Agents. He works with companies of all sizes on solving  business and performance challenges in AI and Machine Learning workloads. He enjoys contributing to open source and working with data. is a Senior Efficient Compute Specialist Solutions Architect at AWS. Romain promotes the benefits of AWS Graviton, EC2 Spot, Karpenter, or Auto-Scaling while helping French customers in their adoption journey. “Always try to achieve more with less” is his motto !

Rust offers different ways to initialize  variables. Recently, I had to create a runtime-initialized variable: existing approaches don't work in this case. I want to describe multiple ways to achieve it in this post.The Rust language allows you to create constants. Two keywords are available:  and .Sometimes a certain value is used many times throughout a program, and it can become inconvenient to copy it over and over. What’s more, it’s not always possible or desirable to make it a variable that gets carried around to each function that needs it. In these cases, the  keyword provides a convenient alternative to code duplication:A static item is a value which is valid for the entire duration of your program (a  lifetime).On the surface,  items seem very similar to : both contain a value, both require type annotations and both can only be initialized with constant functions and values. However,  are notably different in that they represent a location in memory. That means that you can have references to  items and potentially even modify them, making them essentially global variables.Static items do not call  at the end of the program.There are two types of  items: those declared in association with the  keyword and those without.None of the above work with .Trying to compile the previous line returns the following:error[E0015]: cannot call non-const fn `regex::Regex::new` in constants
  |
6 | const REGEXP_WAREHOUSE_ENDPOINT: Regex = Regex::new(r"^WAREHOUSE__(?<index>\d)__ENDPOINT.*").unwrap();
  |                                          ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
  |
  = note: calls in constants are limited to constant functions, tuple structs and tuple variants
The same happens with if we change  to .error[E0015]: cannot call non-const fn `regex::Regex::new` in statics
 --> src/config.rs:6:43
  |
6 | static REGEXP_WAREHOUSE_ENDPOINT: Regex = Regex::new(r"^WAREHOUSE__(?<index>\d)__ENDPOINT.*").unwrap();
  |                                           ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
  |
  = note: calls in statics are limited to constant functions, tuple structs and tuple variants
We need a  variable for the . Neither  nor  work; time to search for something else.When you need something, there's a high chance somebody required it before. If lucky, they created a crate for it. Case in point, the  crate provides a solution.A macro for declaring lazily evaluated statics in Rust.Using this macro, it is possible to have statics that require code to be executed at runtime in order to be initialized. This includes anything requiring heap allocations, like vectors or hash maps, as well as anything that requires non-const function calls to be computed.The usage is straightforward: we wrap the  declaration in a macro.We achieved what we wanted to. Yet, we can do better.Rust 1.80 adds .  is a built-in exact replacement for the  macro.

  // Detect dark theme
  var iframe = document.getElementById('tweet-1816491350235173228-979');
  if (document.body.className.includes('dark-theme')) {
    iframe.src = "https://platform.twitter.com/embed/Tweet.html?id=1816491350235173228&theme=dark"
  }



The documentation of  is straightforward:pub struct LazyLock<T, F = fn() -> T> { /* private fields */ }A value which is initialized on the first access.This type is a thread-safe LazyCell, and can be used in statics. Since initialization may be called from multiple threads, any dereferencing call will block the calling thread if another initialization routine is currently running.At this point, we can use it directly:As an alternative, one can use  from Rust 1.70.pub struct OnceLock<T> { /* private fields */ }A synchronization primitive which can nominally be written to only once.This type is a thread-safe , and can be used in statics. In many simple cases, you can use  instead to get the benefits of this type with less effort:  "looks like"  because it initializes with  on deref! Where OnceLock shines is when LazyLock is too simple to support a given case, as LazyLock doesn’t allow additional inputs to its function after you call .Usage is quite different:Get or initialize the variableIn this post, we described several options to create lazy-initialized variables. Before, we had to rely on the  crate. With Rust 1.80, we can replace it with . If you need additional input after the ,  is your friend.

Welcome to of our FastAPI journey! Yesterday, we explored how to use to handle dynamic URLs.Today, we’re entering the world of and — the backbone of data validation in FastAPI.
🧠 Why Do We Need Request Bodies? Let’s imagine you're building an online registration form for a new user. You need details like name, email, and age. These details are not passed in the URL but rather sent in the .This is where and come into play in FastAPI.
🧩 Real-World Analogy: Pydantic is the Bouncer at a Club Think of your API like a nightclub. You can’t just let anyone in. The bouncer at the door checks if you're:On the list (valid email)Actually a real person (non-empty name)Just like that, is your API’s gatekeeper — it checks if the incoming request body has the correct structure and data types.
🔧 Step-by-Step: Create a POST Endpoint We'll create a FastAPI app that accepts a JSON body with user details.
📁 Create a file called : from fastapi import FastAPI from pydantic import BaseModel
app = FastAPI()
# 🎯 Step 1: Define your request body schema using Pydantic class User(BaseModel): name: str email: str age: int
# 🎯 Step 2: Create a POST endpoint to accept the request body @app.post("/user") def create_user(user: User): return { "message": f"Welcome, {user.name}!", "email": user.email, "age": user.age }
🖥️ Start the FastAPI server: uvicorn user:app --host 0.0.0.0 --port 9002 --reload 📤 Try sending this sample JSON:{ "name": "Utkarsh", "email": "utkarsh@example.com", "age": 28 } ✅ FastAPI will automatically validate the request and return a structured response or helpful error messages.
🧪 Add Validation with Pydantic Let’s enhance the model with proper validation using , default values, and field constraints.
🔧 Prerequisite: Install To use for validating emails, you must install the package.Run this command in your terminal:pip install pydantic[email]
🔧 Step-by-Step: Create a POST Endpoint We'll create a FastAPI app that accepts a JSON body with user details.
📁 Create a file called : from fastapi import FastAPI from pydantic import BaseModel, EmailStr, Field from typing import Optional
app = FastAPI()
class User(BaseModel): name: str = Field(..., min_length=2, max_length=50) email: EmailStr age: Optional[int] = Field(None, ge=18, le=100)
@app.post("/user") def create_user(user: User): return { "message": f"Welcome, {user.name}!", "email": user.email, "age": user.age } : Required string with a minimum length of 2 and a maximum of 50.: Must be a valid email address ( from Pydantic).: Optional integer; if provided, it must be between 18 and 100.
🖥️ Start the FastAPI server: uvicorn user:app --host 0.0.0.0 --port 9004 --reload 📤 Try sending this sample JSON:{ "name": "Utkarsh", "email": "utkarsh@example.com", "age": 16 }
🌍 Real-World Example – Feedback API from fastapi import FastAPI from pydantic import BaseModel, EmailStr, Field
app = FastAPI()
class Feedback(BaseModel): name: str email: EmailStr message: str = Field(..., min_length=10)
@app.post("/feedback") def submit_feedback(feedback: Feedback): return { "status": "received", "from": feedback.name, "email": feedback.email } { "name": "Utkarsh", "email": "Utkarsh@email.com", "message": "Great job with the FastAPI series!" }
📦 Nested Models Example – Customer with Address from fastapi import FastAPI from pydantic import BaseModel
app = FastAPI()
class Address(BaseModel): city: str pincode: int
class Customer(BaseModel): name: str address: Address
@app.post("/customer") def create_customer(customer: Customer): return {"msg": f"{customer.name} from {customer.address.city} added."}
{ "name": "Utkarsh", "address": { "city": "Mumbai", "pincode": 110 } }
